INSERT INTO "Questions" ("QuestionID", "QuestionText", "QuestionType", "DisplayOrder", "IsActive") VALUES (1, 'Bạn có mục tiêu cụ thể nào khi cai thuốc lá không?', 'SingleChoice', 1, true);
