INSERT INTO "Achievement" ("AchievementID", "AchievementName", "Description", "Criteria", "BadgeImage", "PackageType", "SmokeFreeDaysRequired", "MoneySavedRequired", "CigarettesDroppedRequired", "CheckinDaysRequired") VALUES (1, '1 ngày không hút thuốc ', 'Một ngày tuyệt vời! Bạn đã xuất sắc vượt qua ngày đầu tiên không hút thuốc. Hãy tiếp tục phát huy nhé!', 'Smokefree for 1 day', 'https://github.com/THQuis/SWP391_Group5/blob/Mi/image/1day_kohut.png?raw=true', 'Streak', 1, 0.00, 0, 0);
INSERT INTO "Achievement" ("AchievementID", "AchievementName", "Description", "Criteria", "BadgeImage", "PackageType", "SmokeFreeDaysRequired", "MoneySavedRequired", "CigarettesDroppedRequired", "CheckinDaysRequired") VALUES (2, '7 ngày không hút thuốc', 'Bạn đã không hút thuốc một tuần liên tục! Một khởi đầu đầy mạnh mẽ cho hành trình mới.', 'Smokefree for 7 days', 'https://github.com/THQuis/SWP391_Group5/blob/Mi/image/7day_kohut.png?raw=true', 'Streak', 7, NULL, NULL, NULL);
INSERT INTO "Achievement" ("AchievementID", "AchievementName", "Description", "Criteria", "BadgeImage", "PackageType", "SmokeFreeDaysRequired", "MoneySavedRequired", "CigarettesDroppedRequired", "CheckinDaysRequired") VALUES (3, '30 ngày không hút thuốc', 'Bạn đã vượt qua mốc 1 tháng không thuốc lá. Sức khỏe của bạn đang được cải thiện từng ngày!', 'Smokefree for 30 days', 'https://github.com/THQuis/SWP391_Group5/blob/Mi/image/30day_kohut.png?raw=true', 'Streak', 30, NULL, NULL, NULL);
INSERT INTO "Achievement" ("AchievementID", "AchievementName", "Description", "Criteria", "BadgeImage", "PackageType", "SmokeFreeDaysRequired", "MoneySavedRequired", "CigarettesDroppedRequired", "CheckinDaysRequired") VALUES (4, '60 ngày không hút thuốc', 'Bạn đã kiên trì 60 ngày không hút thuốc! Thành tựu này thật đáng tự hào.', 'Smokefree for 60 days', 'https://github.com/THQuis/SWP391_Group5/blob/Mi/image/60day_kohut.png?raw=true', 'Streak', 60, NULL, NULL, NULL);
INSERT INTO "Achievement" ("AchievementID", "AchievementName", "Description", "Criteria", "BadgeImage", "PackageType", "SmokeFreeDaysRequired", "MoneySavedRequired", "CigarettesDroppedRequired", "CheckinDaysRequired") VALUES (5, '90 ngày không hút thuốc', 'Bạn đã không hút thuốc trong 90 ngày liên tiếp! Một bước tiến lớn tới cuộc sống khỏe mạnh hơn.', 'Smokefree for 90 days', 'https://github.com/THQuis/SWP391_Group5/blob/Mi/image/90day_kohut.png?raw=true', 'Streak', 90, NULL, NULL, NULL);
INSERT INTO "Achievement" ("AchievementID", "AchievementName", "Description", "Criteria", "BadgeImage", "PackageType", "SmokeFreeDaysRequired", "MoneySavedRequired", "CigarettesDroppedRequired", "CheckinDaysRequired") VALUES (6, '180 ngày không hút thuốc', 'Nửa năm không hút thuốc! Bạn đã làm điều tuyệt vời cho bản thân và những người thân yêu.', 'Smokefree for 180 days', 'https://github.com/THQuis/SWP391_Group5/blob/Mi/image/180day_kohut.png?raw=true', 'Streak', 180, NULL, NULL, NULL);
